def solve(*args):
    from kafka import KafkaConsumer
    import logging

    logging.basicConfig(level=logging.INFO)
    logger = logging.getLogger(__name__)

    class KafkaEventConsumer:
        def __init__(self, topics, handlers):
            self.consumer = KafkaConsumer(*topics, auto_offset_reset='earliest', enable_auto_commit=True)
            self.handlers = handlers

        def consume(self):
            for message in self.consumer:
                logger.info(f"Received message: {message.value} on topic: {message.topic}")
                self.handle_event(message)

        def handle_event(self, message):
            handler = self.handlers.get(message.topic)
            if handler:
                handler(message.value)
            else:
                logger.warning(f"No handler found for topic: {message.topic}")

    def start_consumer(topics, handlers):
        consumer = KafkaEventConsumer(topics, handlers)
        consumer.consume()

    return start_consumer
